import { useEffect, useMemo, useRef, useState } from 'react';
import {
  Button as AriaButton,
  MenuTrigger as AriaMenuTrigger,
  Menu as AriaMenu,
  MenuItem as AriaMenuItem,
  Popover as AriaPopover,
} from 'react-aria-components';
import { FilterLines } from '@untitledui/icons/FilterLines';
import { SlashCircle01 } from '@untitledui/icons/SlashCircle01';
import { CheckCircle } from '@untitledui/icons/CheckCircle';
import { ChevronDown } from '@untitledui/icons/ChevronDown';
import { XClose } from '@untitledui/icons/XClose';
import { Badge } from '@/vendor/untitled-ui/base/badges/badges';
import { Checkbox } from '@/components/atoms/Checkbox';
import { RadioButton } from '@/components/atoms/RadioButton/RadioButton';
import { RadioGroup as AriaRadioGroup } from 'react-aria-components';
import { SearchLg } from '@untitledui/icons/SearchLg';
import { Button } from '@/components/atoms/Button';
import { InputField } from '@/components/atoms/Input';
import { cx } from '@/utils/cx';
import { useChipOverflow } from './useChipOverflow';
import { WithDataId } from '@/types/withDataId';
import { Tooltip } from '@/components/atoms/Tooltip';
import { deepEqual } from '@/utils/deepEqual/deepEqual';
import { isEmptyObject } from '@/utils/isEmptyObject/isEmptyObject';

type Values = string | string[] | number | number[] | object | null;

export type RequiredFieldProps<V> = {
  value: V;
  onChange: (value: V) => void;
  context?: 'panel' | 'chip';
};

export type ChipDescriptor<V> = {
  key: string;
  label: React.ReactNode;
  /**
   * Partial value merged into the field on chip remove. When omitted the chip
   * is not individually removable (no X button), but still clickable to open
   * the chip popover.
   */
  partialEmpty?: Partial<V>;
  /**
   * When true and the chip is non-removable, render a dropdown chevron icon
   * to signal the chip opens an editor.
   */
  chevron?: boolean;
  /**
   * Override the popover content for this specific chip. When omitted, the
   * field's Component is used (same editor as the panel). Useful when one
   * chip should open a narrower editor than the field as a whole.
   */
  Component?: React.ComponentType<
    RequiredFieldProps<V> & WithDataId & Record<string, unknown>
  >;
};

type TypedCallback<V> = {
  [K in keyof V]: {
    name: K;
    emptyValue?: V[K];
    count?: (value: V[K]) => number;
    chips?: (value: V[K]) => ChipDescriptor<V[K]>[];
    field: {
      Component: React.ComponentType<
        RequiredFieldProps<V[K]> & WithDataId & Record<string, unknown>
      >;
      props?: Record<string, unknown>;
    };
  };
}[keyof V];

export const FILTER_VARIANTS = {
  DEFAULT: 'default',
  MINIMAL: 'minimal',
} as const;

export type FilterVariant =
  (typeof FILTER_VARIANTS)[keyof typeof FILTER_VARIANTS];

export type FilterTexts = {
  btnFilter: string;
  btnClearAll: string;
  btnApply: string;
  btnCollapse?: string;
  btnRemoveFilter?: string;
  btnAppliedFilters?: string;
  inputSearchPlaceholder?: string;
};

export type FilterProps<T> = {
  initValues: T;
  onSubmit: (values: T) => void;
  onClearAll?: () => void;
  groups: Record<
    string,
    {
      label: React.ReactNode;
      fields: TypedCallback<T>[];
    }
  >;
  onFieldChange?: (
    fieldName: keyof T,
    value: T[keyof T],
    currentValues: T,
  ) => Partial<T> | void;
  className?: string;
  chipOverflow?: boolean;
  setMoreLabel?: (count: number) => string;
  t?: FilterTexts;
  isEditable?: boolean;
  /**
   * When true, the "Clear all" action stays visible even when no filters are
   * applied. Defaults to false — preserves the prior behavior of hiding the
   * action until at least one chip is present.
   */
  alwaysShowClearAll?: boolean;
  variant?: FilterVariant;
} & WithDataId;

function isFieldApplied(value: Values, emptyValue?: Values): boolean {
  if (emptyValue !== undefined) return !deepEqual(value, emptyValue);

  if (value == null) return false;
  if (value === '') return false;
  if (Array.isArray(value)) return value.length > 0;

  if (typeof value === 'object') return !isEmptyObject(value);

  return true;
}

function getValueCount(value: Values): number {
  if (Array.isArray(value)) return value.length;

  if (value !== null && typeof value === 'object') {
    // Count non-nullish keys as "active" entries
    return Object.values(value as Record<string, unknown>).filter(
      (v) => v != null && v !== '',
    ).length;
  }
  return 1;
}

export function Filter<T extends { [field: string]: Values }>({
  initValues,
  groups = {},
  className,
  onSubmit,
  onClearAll,
  onFieldChange,
  chipOverflow = false,
  setMoreLabel,
  isEditable = true,
  alwaysShowClearAll = false,
  variant = FILTER_VARIANTS.DEFAULT,
  t = { ...defaultTexts },
  'data-id': dataId,
}: FilterProps<T>) {
  const [isOpen, setIsOpen] = useState(false);
  const [values, setValues] = useState<T>(() => ({ ...initValues }));
  const [selectedGroup, setSelectedGroup] = useState(
    () => Object.keys(groups)[0] || '',
  );
  const [isExpanded, setIsExpanded] = useState(false);
  const chipsRef = useRef<HTMLDivElement>(null);
  const prevInitValuesRef = useRef(initValues);

  const applied = useMemo(
    () =>
      Object.entries(groups).flatMap(([groupKey, group]) => {
        return group.fields.flatMap((field) => {
          const fieldValue = initValues[field.name];
          const { Component, props } = field.field;
          const baseChip = {
            fieldName: field.name,
            Component,
            isEditable,
            fieldProps: props,
            onClose: () => {
              setValues((current) => {
                const changed = !deepEqual(current[field.name], fieldValue);
                if (changed) onSubmit({ ...current });
                return current;
              });
            },
          };

          if (field.chips) {
            const descriptors = field.chips(fieldValue);
            if (descriptors.length === 0) return [];
            return descriptors.map((desc) => ({
              ...baseChip,
              Component: desc.Component ?? baseChip.Component,
              id: `${groupKey}-${String(field.name)}-${desc.key}`,
              label: desc.label,
              chevron: desc.chevron,
              onRemove: desc.partialEmpty
                ? () => {
                    const merged = {
                      ...(fieldValue as object),
                      ...(desc.partialEmpty as object),
                    } as typeof fieldValue;
                    const next =
                      field.emptyValue !== undefined &&
                      deepEqual(merged, field.emptyValue)
                        ? field.emptyValue
                        : merged;
                    onSubmit({ ...initValues, [field.name]: next });
                  }
                : undefined,
            }));
          }

          if (!isFieldApplied(fieldValue, field.emptyValue)) return [];

          const count = getValueCount(fieldValue);
          const labelSuffix = ` (${count})`;

          const listProps = props as
            | {
                isMulti?: boolean;
                options?: { label: string; value: string | number }[];
              }
            | undefined;

          const resolvedLabel = listProps?.isMulti ? (
            <>
              {group.label}
              <span className="text-quaternary">{labelSuffix}</span>
            </>
          ) : (
            listProps?.options?.find((item) =>
              deepEqual(item.value, fieldValue),
            )?.label || group.label
          );

          return [
            {
              ...baseChip,
              id: `${groupKey}-${String(field.name)}`,
              label: resolvedLabel,
              chevron: false,
              onRemove: () => {
                onSubmit({
                  ...initValues,
                  [field.name]: field.emptyValue ?? null,
                });
              },
            },
          ];
        });
      }),
    [groups, initValues, onSubmit, isEditable],
  );

  const { hiddenCount, clipWidth } = useChipOverflow({
    containerRef: chipsRef,
    chipCount: applied.length,
    chipOverflow,
    isExpanded,
  });

  useEffect(() => {
    if (applied.length === 0) setIsExpanded(false);
  }, [applied.length]);

  const handleClearAll = () => {
    const clearedValues = {} as T;

    Object.keys(groups).forEach((groupKey) => {
      const group = groups[groupKey];
      group.fields.forEach((field) => {
        if (field.emptyValue !== undefined) {
          clearedValues[field.name] = field.emptyValue;
        } else {
          const current = initValues[field.name];
          if (
            typeof current === 'object' &&
            current !== null &&
            !Array.isArray(current)
          ) {
            // Reset each key to null, preserving object shape
            clearedValues[field.name] = Object.fromEntries(
              Object.keys(current).map((k) => [k, null]),
            ) as T[typeof field.name];
          } else {
            clearedValues[field.name] = null as T[typeof field.name];
          }
        }
      });
    });

    if (onClearAll) {
      onClearAll();
    } else {
      onSubmit(clearedValues);
    }

    // Reset values so reopening the panel shows cleared state immediately,
    // even if the consumer updates initValues asynchronously after onClearAll.
    setValues(clearedValues);
    setIsOpen(false);
  };

  const handleApply = () => {
    onSubmit(values);
    setIsOpen(false);
  };

  useEffect(() => {
    if (prevInitValuesRef.current !== initValues) {
      prevInitValuesRef.current = initValues;
      setValues({ ...initValues });
    }
  }, [initValues]);

  return (
    <div
      className={cx(
        'flex gap-2 items-start',
        chipOverflow && isExpanded && 'flex-wrap',
        className,
      )}
    >
      <AriaMenuTrigger
        isOpen={isOpen}
        onOpenChange={setIsOpen}
      >
        {isEditable && (
          <Button
            iconLeading={FilterLines}
            color="secondary"
            className={cx(variant === FILTER_VARIANTS.MINIMAL && 'h-10')}
            onPress={() => setIsOpen(true)}
            data-id={`${dataId}-trigger`}
            // Default variant uses the visible "Filter" text as its accessible
            // name; minimal hides that text, so we set aria-label to combine
            // the action label with the current applied count.
            aria-label={
              variant === FILTER_VARIANTS.MINIMAL
                ? `${t.btnFilter}, ${applied.length}`
                : undefined
            }
          >
            {variant === FILTER_VARIANTS.MINIMAL ? (
              <Badge
                color={applied.length > 0 ? 'brand' : 'gray'}
                className="h-5 leading-none"
              >
                {applied.length}
              </Badge>
            ) : (
              t.btnFilter
            )}
          </Button>
        )}

        <AriaPopover
          containerPadding={0}
          className="rounded-lg bg-primary shadow-lg ring ring-secondary_alt"
        >
          <div className="grid grid-cols-[250px_250px] border-b border-secondary_alt">
            <AriaMenu
              className="flex flex-col gap-0.5 border-r border-secondary_alt px-1.5 py-1 outline-hidden select-none overflow-y-auto min-h-82 max-h-120"
              selectionMode="multiple"
            >
              {Object.keys(groups).map((key) => {
                const group = groups[key];
                const count =
                  group?.fields?.reduce((acc, field) => {
                    const value = values[field.name];
                    if (field.chips) {
                      return acc + field.chips(value).length;
                    }
                    if (!isFieldApplied(value, field.emptyValue)) return acc;
                    if (field.count) {
                      const fieldCount = field.count(value);
                      return acc + fieldCount;
                    }
                    if (Array.isArray(value)) return acc + value.length;

                    if (value !== null && typeof value === 'object') {
                      // Count non-nullish keys as "active" entries
                      return Object.values(
                        value as Record<string, unknown>,
                      ).filter((v) => v != null && v !== '').length;
                    }
                    return acc + 1;
                  }, 0) ?? 0;

                return (
                  <AriaMenuItem
                    key={key}
                    id={key}
                    className={cx(
                      'flex justify-between cursor-pointer rounded-md px-2.5 py-2 hover:bg-primary_hover font-normal w-full text-left text-secondary text-sm outline-hidden',
                      selectedGroup === key &&
                        'bg-primary_hover text-secondary_hover',
                    )}
                    onPress={() => setSelectedGroup(key)}
                  >
                    <span>{groups[key].label}</span>
                    <Badge
                      type="modern"
                      className={cx('invisible', count > 0 && 'visible')}
                    >
                      {count}
                    </Badge>
                  </AriaMenuItem>
                );
              })}
            </AriaMenu>

            <div className="px-2 py-2 min-h-82 max-h-120 overflow-y-auto">
              <div className="flex flex-col gap-4">
                {groups[selectedGroup]?.fields.map((field) => {
                  const { Component, props } = field.field;

                  if (!Component) return null;

                  return (
                    <Component
                      key={String(field.name)}
                      {...props}
                      data-id={`${dataId}-${String(field.name)}`}
                      context="panel"
                      value={values[field.name]}
                      onChange={(value) => {
                        setValues((prev) => {
                          const updated = { ...prev, [field.name]: value };
                          const extra = onFieldChange?.(
                            field.name,
                            value as T[keyof T],
                            prev,
                          );
                          return extra ? { ...updated, ...extra } : updated;
                        });
                      }}
                    />
                  );
                })}
              </div>
            </div>
          </div>
          <div className="flex p-4 gap-4">
            <Button
              iconLeading={SlashCircle01}
              color="secondary"
              size="sm"
              className="w-full"
              onPress={handleClearAll}
              data-id={`${dataId}-clearAll`}
            >
              {t.btnClearAll}
            </Button>
            <Button
              iconLeading={CheckCircle}
              size="sm"
              className="w-full"
              onPress={handleApply}
              data-id={`${dataId}-apply`}
            >
              {t.btnApply}
            </Button>
          </div>
        </AriaPopover>
      </AriaMenuTrigger>

      {variant !== FILTER_VARIANTS.MINIMAL &&
        applied.length > 0 &&
        isEditable && (
          <div
            aria-hidden="true"
            className="h-7 w-px bg-border-secondary self-center shrink-0"
          />
        )}

      {variant !== FILTER_VARIANTS.MINIMAL && applied.length > 0 ? (
        <div
          className={cx(
            'flex items-center gap-2',
            chipOverflow && !isExpanded && 'min-w-0',
            chipOverflow && isExpanded && 'contents',
          )}
        >
          <div
            ref={chipsRef}
            role="group"
            aria-label={t.btnAppliedFilters}
            className={cx(
              'flex items-center gap-2',
              chipOverflow && !isExpanded
                ? 'flex-1 flex-nowrap overflow-clip [overflow-clip-margin:6px] min-w-0'
                : 'contents',
            )}
            style={
              chipOverflow && !isExpanded && clipWidth !== undefined
                ? { maxWidth: clipWidth }
                : undefined
            }
          >
            {applied.map((chip) => (
              <div
                key={chip.id}
                className="relative"
              >
                <AriaMenuTrigger
                  onOpenChange={(open) => {
                    if (!open) chip.onClose();
                  }}
                >
                  <Button
                    color="secondary"
                    data-id={`${dataId}-chipButton`}
                    iconTrailing={
                      isEditable && !chip.onRemove && chip.chevron
                        ? ChevronDown
                        : undefined
                    }
                  >
                    <span className={isEditable && chip.onRemove ? 'mr-6' : ''}>
                      {chip.label}
                    </span>
                  </Button>
                  <AriaPopover
                    placement="bottom left"
                    className="min-w-60 max-w-80 rounded-lg bg-primary shadow-lg ring ring-secondary_alt"
                  >
                    <div className="px-1.5 py-1 max-h-92 overflow-y-auto">
                      <ChipPopoverContent
                        chip={chip}
                        value={values[chip.fieldName]}
                        setValues={setValues}
                        onFieldChange={onFieldChange}
                        data-id={`${dataId}-chip-${String(chip.fieldName)}`}
                        isEditable={isEditable}
                      />
                    </div>
                  </AriaPopover>
                </AriaMenuTrigger>

                {isEditable && chip.onRemove && (
                  <AriaButton
                    aria-label={t.btnRemoveFilter}
                    className="absolute right-3 top-[calc(50%_-_10px)] z-10 flex cursor-pointer items-center justify-center rounded-lg p-0 text-fg-quaternary"
                    onPress={chip.onRemove}
                  >
                    <XClose
                      aria-hidden="true"
                      className="size-5"
                    />
                  </AriaButton>
                )}
              </div>
            ))}
          </div>
          {chipOverflow && (hiddenCount > 0 || isExpanded) && (
            <Button
              color="tertiary"
              className="shrink-0"
              onPress={() => setIsExpanded((prev) => !prev)}
              data-id={`${dataId}-toggleExpand`}
            >
              {isExpanded
                ? t.btnCollapse
                : setMoreLabel
                  ? setMoreLabel(hiddenCount)
                  : `+${hiddenCount} more`}
            </Button>
          )}
          {isEditable && (
            <Button
              aria-label={`${t.btnClearAll} ${t.btnAppliedFilters}`.toLowerCase()}
              color="tertiary"
              className="shrink-0"
              onPress={handleClearAll}
              data-id={`${dataId}-chipsClearAll`}
            >
              {t.btnClearAll}
            </Button>
          )}
        </div>
      ) : null}

      {applied.length === 0 && isEditable && alwaysShowClearAll && (
        <>
          <div
            aria-hidden="true"
            className="h-7 w-px bg-border-secondary self-center shrink-0"
          />
          <Button
            aria-label={`${t.btnClearAll} ${t.btnAppliedFilters}`.toLowerCase()}
            color="tertiary"
            className="shrink-0"
            onPress={handleClearAll}
            data-id={`${dataId}-chipsClearAll`}
          >
            {t.btnClearAll}
          </Button>
        </>
      )}
    </div>
  );
}

function ChipPopoverContent<T extends { [field: string]: Values }>({
  chip,
  value,
  setValues,
  onFieldChange,
  'data-id': dataId,
  isEditable,
}: {
  chip: {
    fieldName: keyof T;
    Component: React.ComponentType<
      RequiredFieldProps<T[keyof T]> & WithDataId & Record<string, unknown>
    >;
    fieldProps?: Record<string, unknown>;
  };
  value: T[keyof T];
  setValues: React.Dispatch<React.SetStateAction<T>>;
  onFieldChange?: (
    fieldName: keyof T,
    value: T[keyof T],
    currentValues: T,
  ) => Partial<T> | void;
  isEditable?: boolean;
} & WithDataId) {
  return (
    <chip.Component
      {...chip.fieldProps}
      data-id={dataId}
      context="chip"
      value={value}
      onChange={(newValue) => {
        if (!isEditable) return;
        setValues((prev) => {
          const updated = { ...prev, [chip.fieldName]: newValue };
          const extra = onFieldChange?.(
            chip.fieldName,
            newValue as T[keyof T],
            prev,
          );
          return extra ? { ...updated, ...extra } : updated;
        });
      }}
    />
  );
}

type ListProps<V extends Values> = RequiredFieldProps<V> & {
  options?: {
    label: string;
    value: string | number;
    supportingText?: string;
  }[];
  isMulti?: boolean;
  withSearch?: boolean;
  searchPlaceholder?: string;
} & WithDataId;

// Sized to fit inside the panel (max-h-120 wrapper) and chip (max-h-92 wrapper)
// popovers respectively. Keep in sync with those wrappers.
const LIST_MAX_H = {
  panel: 'max-h-116',
  chip: 'max-h-80',
} as const;

function List<V extends Values>({
  options = [],
  onChange,
  value,
  isMulti = false,
  withSearch = false,
  searchPlaceholder,
  context,
  'data-id': dataId,
}: ListProps<V>) {
  // Chip popover should close on pick when single-select; multi-select stays
  // open so users can toggle several. Panel context always keeps the inner
  // menu in "multiple" mode to avoid bubbling close-on-action up to the
  // surrounding panel MenuTrigger.
  const shouldAutoClose = !isMulti && context === 'chip';
  const [searchTerm, setSearchTerm] = useState('');

  const filteredOptions = options.filter((item) => {
    return (
      item.label.toLowerCase().includes(searchTerm.trim().toLowerCase()) ||
      (item.supportingText &&
        item.supportingText
          .toLowerCase()
          .includes(searchTerm.trim().toLowerCase()))
    );
  });
  const multiValues = Array.isArray(value)
    ? (value as (string | number)[])
    : [];

  return (
    <div className={cx('flex flex-col gap-1', LIST_MAX_H[context ?? 'chip'])}>
      {withSearch && (
        <InputField
          placeholder={searchPlaceholder}
          icon={SearchLg}
          value={searchTerm}
          onChange={setSearchTerm}
          data-id={`${dataId}-searchInput`}
        />
      )}
      <AriaRadioGroup
        value={value != null ? String(value) : ''}
        onChange={() => {}}
        aria-hidden="true"
        className="contents"
      >
        <AriaMenu
          className="h-min overflow-y-auto overscroll-none outline-hidden select-none flex flex-col gap-0.5"
          selectionMode={shouldAutoClose ? 'single' : 'multiple'}
          selectedKeys={multiValues}
        >
          {filteredOptions.map((item) => {
            const isSelected = isMulti
              ? multiValues.includes(item.value)
              : value === item.value;

            return (
              <AriaMenuItem
                id={item.value}
                key={item.value}
                className={cx(
                  'w-full px-2.5 py-2 cursor-pointer outline-hidden flex items-center gap-2 text-secondary hover:bg-primary_hover rounded-md',
                  isSelected && 'bg-primary_hover text-secondary_hover',
                )}
                onPress={() => {
                  if (isMulti) {
                    const newValue = isSelected
                      ? multiValues.filter((v) => v !== item.value)
                      : [...multiValues, item.value];
                    onChange(
                      newValue.length > 0 ? (newValue as V) : (null as V),
                    );
                  } else {
                    const updatedValue = (isSelected ? null : item.value) as V;
                    onChange(updatedValue);
                  }
                }}
                data-id={`${dataId}-option-${item.value}`}
              >
                {isMulti ? (
                  <Checkbox
                    isSelected={isSelected}
                    onChange={() => {}}
                    className="pointer-events-none shrink-0"
                    aria-hidden="true"
                    data-id={`${dataId}-checkbox-${item.value}`}
                  />
                ) : (
                  <RadioButton
                    value={String(item.value)}
                    className="pointer-events-none shrink-0"
                    aria-hidden="true"
                    data-id={`${dataId}-radio-${item.value}`}
                  />
                )}
                <div className="flex flex-col gap-y-1 text-sm flex-1 min-w-0">
                  <span className="font-medium text-primary">{item.label}</span>

                  {item.supportingText && (
                    <Tooltip
                      data-id={`${dataId}-option-supporting-text-tooltip-${item.value}`}
                      title={item.supportingText}
                      triggerProps={{
                        className:
                          'w-full overflow-hidden text-ellipsis text-nowrap text-left',
                      }}
                    >
                      <span className="font-normal text-quaternary">
                        {item.supportingText}
                      </span>
                    </Tooltip>
                  )}
                </div>
              </AriaMenuItem>
            );
          })}
        </AriaMenu>
      </AriaRadioGroup>
    </div>
  );
}

Filter.List = List;

const defaultTexts = {
  btnFilter: 'Filter',
  btnClearAll: 'Clear all',
  btnApply: 'Apply filters',
  btnCollapse: 'Collapse',
  btnRemoveFilter: 'Remove filter',
  btnAppliedFilters: 'Applied filters',
};
